      <div style="font-size:10px;color:var(--gray-l);margin-top:8px">\uACF5\uC720\uCE74\uB4DC \uC804\uC6A9 \uBC30\uACBD\uC785\uB2C8\uB2E4. \uC2A4\uD2B8\uB9AC\uBA38 \uC0C1\uC138 \uD5E4\uB354 \uBC30\uACBD\uACFC \uBCC4\uB3C4\uB85C \uC800\uC7A5\uB429\uB2C8\uB2E4.</div>
