                <li><b>\uC5EC\uC131 \uC2A4\uD2B8\uB9AC\uBA38 \uAC04 \uB05D\uC7A5\uC804</b>\uC758 \uACBD\uC6B0, \uD3A8\uCF54 \uC2A4\uD0C0\uD06C\uB798\uD504\uD2B8 \uAC8C\uC2DC\uD310 <b>\uACBD\uAE30 \uACB0\uACFC\uD0ED</b>\uC5D0 \uAE00\uC774 \uB4F1\uB85D\uB418\uACE0 \u2192 \uADF8 \uACB0\uACFC\uAC00 <b>\uC6B0\uB9AC \uC571 \uAE30\uB85D\uC73C\uB85C \uB4F1\uB85D\uB41C \uACBD\uC6B0</b> \uBC18\uC601\uB429\uB2C8\uB2E4</li>
